  1	/**
  2	 * Provides the main layout for the application using PatternFly, incorporating a header, navigation sidebar,
  3	 * and content area. It dynamically adjusts navigation based on routing, supports a sidebar toggle, and
  4	 * ensures accessibility with a "Skip to Content" link. Excludes header and sidebar on the login page for a
  5	 * simplified UI.
  6	 *
  7	 * @module appLayout
  8	 */
  9	import * as React from 'react';
 10	import { useTranslation } from 'react-i18next';
 11	import { NavLink, useLocation } from 'react-router-dom';
 12	import {
 13	  Brand,
 14	  Button,
 15	  Masthead,
 16	  MastheadBrand,
 17	  MastheadContent,
 18	  MastheadMain,
 19	  MastheadToggle,
 20	  Nav,
 21	  NavItem,
 22	  NavList,
 23	  Page,
 24	  PageSidebar,
 25	  PageSidebarBody,
 26	  SkipToContent
 27	} from '@patternfly/react-core';
 28	import { BarsIcon } from '@patternfly/react-icons';
 29	import { helpers } from '../../helpers';
 30	import { IAppRoute, routes } from '../../routes';
 31	import { AppToolbar } from './viewLayoutToolbar';
 32	
 33	interface AppLayoutProps {
 34	  children: React.ReactNode;
 35	  titleImg?: string;
 36	  uiName?: string;
 37	}
 38	
 39	const AppLayout: React.FC<AppLayoutProps> = ({
 40	  children,
 41	  titleImg = helpers.getTitleImg(),
 42	  uiName = helpers.UI_NAME
 43	}) => {
 44	  const { t } = useTranslation();
 45	  const [sidebarOpen, setSidebarOpen] = React.useState(true);
 46	
 47	  const Header = (
 48	    <Masthead>
 49	      <MastheadToggle>
 50	        <Button
 51	          variant="plain"
 52	          onClick={() => setSidebarOpen(!sidebarOpen)}
 53	          aria-label="Global navigation"
 54	          ouiaId="global-navigation"
 55	        >
 56	          <BarsIcon />
 57	        </Button>
 58	      </MastheadToggle>
 59	      <MastheadMain>
 60	        <MastheadBrand>
 61	          <Brand alt={t('view.alt-logo', { name: uiName })} heights={{ default: '36px' }}>
 62	            <source srcSet={titleImg} />
 63	          </Brand>
 64	        </MastheadBrand>
 65	      </MastheadMain>
 66	      <MastheadContent>
 67	        <AppToolbar />
 68	      </MastheadContent>
 69	    </Masthead>
 70	  );
 71	
 72	  const location = useLocation();
 73	
 74	  const renderNavItem = (route: IAppRoute, index: number) => (
 75	    <NavItem key={`${route.label}-${index}`} id={`${route.label}-${index}`} isActive={route.path === location.pathname}>
 76	      <NavLink to={route.path}>{route.label}</NavLink>
 77	    </NavItem>
 78	  );
 79	
 80	  // FixMe: PF spelling bug in attr "forwardScrollAriaLabel"
 81	  const Navigation = (
 82	    <Nav id="nav-primary-simple">
 83	      <NavList id="nav-list-simple" forwardScrollAriaLabel="Scroll forward">
 84	        {routes.map((route, idx) => route.label && renderNavItem(route, idx))}
 85	      </NavList>
 86	    </Nav>
 87	  );
 88	
 89	  const Sidebar = (
 90	    <PageSidebar>
 91	      <PageSidebarBody>{Navigation}</PageSidebarBody>
 92	    </PageSidebar>
 93	  );
 94	
 95	  const pageId = 'primary-app-container';
 96	
 97	  const PageSkipToContent = (
 98	    <SkipToContent
 99	      onClick={event => {
100	        event.preventDefault();
101	        const primaryContentContainer = document.getElementById(pageId);
102	        if (primaryContentContainer) {
103	          primaryContentContainer.focus();
104	        }
105	      }}
106	      href={`#${pageId}`}
107	    >
108	      Skip to Content
109	    </SkipToContent>
110	  );
111	
112	  return (
113	    <Page mainContainerId={pageId} masthead={Header} sidebar={sidebarOpen && Sidebar} skipToContent={PageSkipToContent}>
114	      {children}
115	    </Page>
116	  );
117	};
118	
119	export { AppLayout as default, AppLayout, type AppLayoutProps };

